function replaceSuccess(){if(!submitted)return false;var wrapper=host.closest('.mf-form-wrapper')||document.querySelector('.mf-form-wrapper:has(.mfp-bulgaria),.mf-form-wrapper:has(.bg-success-shell)');if(wrapper&&wrapper.querySelector('.bg-success-shell')){revealSuccessHost(wrapper,wrapper.querySelector('.bg-success-shell').parentElement);hideNativeSuccess(wrapper);return true}var nodes=[].slice.call(document.querySelectorAll('.mf-success-message,.mf-postsubmit-pane,.mf-success,.alert-success,.card,.mf-form-wrapper,.module-content'));for(var i=0;i<nodes.length;i++){var txt=(nodes[i].textContent||'').replace(/\s+/g,' ');var visible=!!(nodes[i].offsetWidth||nodes[i].offsetHeight||nodes[i].getClientRects().length);if(txt.indexOf('Submission received')>-1||txt.indexOf('Application received')>-1||txt.indexOf('Submission ID')>-1||txt.indexOf('Reference:')>-1){if(!visible&&txt.indexOf('Submission ID')<0&&txt.indexOf('Reference:')<0)continue;var scope=nodes[i].closest('.mf-form-wrapper')||wrapper||nodes[i].parentElement||document;var anchor=(scope.querySelector&&scope.querySelector('[id^="mf-fields-container-"],.mf-fields-container'))||nodes[i].parentElement||nodes[i];if(anchor&&!anchor.querySelector('.bg-success-shell')){anchor.innerHTML=successMarkup();revealSuccessHost(scope,anchor);hideNativeSuccess(scope);scrollToStepTop();return true}revealSuccessHost(scope,anchor);hideNativeSuccess(scope);return true}}return false}
