@import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=Inter:wght@300;400;500;600;700&display=swap');
.mfp.mfp-bulgaria{--bg-parch:#f5f0e8;--bg-surface:#fff;--bg-dark:#1a1410;--bg-rose:#c94f6d;--bg-rose-soft:#fdf0f3;--bg-green:#2d5a3d;--bg-green-soft:#edf6f0;--bg-gold:#c8853a;--bg-gold-soft:#fdf4ec;--bg-muted:#7c6e62;--bg-border:#e6ddd2;--bg-line:#ded3c7;font-family:'Inter',system-ui,-apple-system,'Segoe UI',sans-serif;color:var(--bg-dark);background:var(--bg-parch);width:100%!important;max-width:760px!important;margin:0 auto!important;padding:0!important;box-sizing:border-box;overflow:visible!important}
.mfp-bulgaria,.mfp-bulgaria *{box-sizing:border-box}
.mfp-bulgaria .bg-card{overflow:visible;border:1px solid var(--bg-border);border-radius:24px;background:var(--bg-surface);box-shadow:0 24px 48px rgba(26,20,16,.16)}
