.mfp-bulgaria .bg-checks .mf-field-label{display:none!important}
.mfp-bulgaria .bg-checks .mf-option-item{display:flex!important;align-items:flex-start!important;gap:12px!important;border:1px solid var(--bg-border)!important;border-radius:14px!important;background:#faf8f5!important;padding:13px 14px!important}
.mfp-bulgaria .bg-checks .mf-option-control{width:19px!important;height:19px!important;margin:2px 0 0!important;accent-color:var(--bg-green)!important;flex:0 0 auto!important}
.mfp-bulgaria .bg-actions{display:flex;align-items:center;justify-content:space-between;margin-top:30px;padding-top:22px;border-top:1px solid var(--bg-border)}
.mfp-bulgaria .bg-actions span{color:var(--bg-muted);font-size:12px;font-weight:600}
.mfp-bulgaria .bg-back,.mfp-bulgaria .bg-next,.mfp-bulgaria .bg-submit{border:0;border-radius:999px;padding:10px 24px;font-family:'Inter',system-ui,sans-serif;font-size:14px;line-height:20px;font-weight:700;cursor:pointer;transition:all .16s ease}
.mfp-bulgaria .bg-back{border:1px solid var(--bg-border);background:#fff;color:var(--bg-muted)}
.mfp-bulgaria .bg-back:disabled{opacity:.32;cursor:not-allowed}
.mfp-bulgaria .bg-next{background:var(--bg-rose);color:#fff}
.mfp-bulgaria .bg-submit{background:var(--bg-green);color:#fff}
.mfp-bulgaria .bg-next:hover:not(:disabled),.mfp-bulgaria .bg-submit:hover:not(:disabled){transform:translateY(-1px);filter:brightness(.96)}
.mfp-bulgaria .bg-next:disabled,.mfp-bulgaria .bg-submit:disabled{opacity:.4;cursor:not-allowed}
.mfp.mfp-bulgaria.bg-success-shell{max-width:760px!important}
.mfp-bulgaria .bg-stepper-success{margin-bottom:20px}
.mfp-bulgaria .bg-success-panel{display:grid;justify-items:center;text-align:center;padding:34px 24px 10px}
.mfp-bulgaria .bg-success-check{display:flex;align-items:center;justify-content:center;width:72px;height:72px;border-radius:999px;background:var(--bg-green);color:#fff;font-size:38px;line-height:1;margin-bottom:18px}
.mfp-bulgaria .bg-success-panel h2{font-size:38px;line-height:46px}
.mfp-bulgaria .bg-success-panel p{max-width:430px;margin:12px auto 0;color:var(--bg-muted);font-size:15px;line-height:24px}
.mfp-bulgaria .bg-success-panel strong{color:var(--bg-dark)}
.mfp-bulgaria .bg-success-panel blockquote{margin:4px 0 22px;color:var(--bg-muted);font-family:'DM Serif Display',Georgia,serif;font-size:18px;line-height:26px;font-style:normal}
.mfp-bulgaria .bg-restart{border:0;border-radius:999px;background:var(--bg-rose);color:#fff;padding:12px 30px;font-family:'Inter',system-ui,sans-serif;font-size:14px;font-weight:700;line-height:20px;cursor:pointer}
.mfp-bulgaria .bg-footer{margin:18px 0 0;text-align:center;color:var(--bg-muted);font-size:12px;line-height:18px}
.mf-form-wrapper:has(.mfp-bulgaria),.mf-form-wrapper:has(.mfp-bulgaria) .mf-form,.mf-form-wrapper:has(.mfp-bulgaria) .mf-form-inner,.mf-form-wrapper:has(.mfp-bulgaria) .mf-fields-container{overflow:visible!important}
.mf-form-wrapper:has(.bg-success-shell) .mf-success-message,.mf-form-wrapper:has(.bg-success-shell) .mf-postsubmit-pane{display:none!important}
.mfp-bulgaria .mf-form-title,.mfp-bulgaria .mf-form-description,.mfp-bulgaria .mf-success-message,.mfp-bulgaria+.mf-form-actions,.mf-form-wrapper:has(.mfp-bulgaria) .mf-form-actions{display:none!important}
.mf-form-wrapper>.mf-form-inner .mfp.mfp-bulgaria{width:100%!important;max-width:760px!important;margin:0 auto!important;padding:0!important;background:var(--bg-parch)!important}
@media(max-width:720px){.mfp.mfp-bulgaria{max-width:100%!important}.mfp-bulgaria .bg-card{border-radius:20px}.mfp-bulgaria .bg-hero{height:250px}.mfp-bulgaria .bg-hero-copy{padding:28px}.mfp-bulgaria .bg-hero-copy h1{font-size:46px}.mfp-bulgaria .bg-thumb{display:none}.mfp-bulgaria .bg-body{padding:28px 22px 30px}.mfp-bulgaria .bg-step{min-width:54px}.mfp-bulgaria .bg-step em{display:none}.mfp-bulgaria .bg-line{width:22px;margin-left:3px;margin-right:3px}.mfp-bulgaria .bg-grid-2,.mfp-bulgaria .mf-row,.mfp-bulgaria .mf-option-group--cards{grid-template-columns:1fr!important}.mfp-bulgaria .bg-actions{gap:10px}.mfp-bulgaria .bg-back,.mfp-bulgaria .bg-next,.mfp-bulgaria .bg-submit{padding:10px 18px}}
/*MF-HEROHEAD-FIX-20260626*/.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy h1{color:#fff!important;font-family:'DM Serif Display',Georgia,serif!important}.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy h1 *{color:#fff!important}.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy .bg-eyebrow,.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy p{color:rgba(255,255,255,.9)!important}

customScripts.bulgaria_wizard:
(function(root){
var host=(root&&root.closest&&root.closest('.mfp-bulgaria'))||(root&&root.querySelector&&root.querySelector('.mfp-bulgaria'))||document.querySelector('.mfp-bulgaria');
if(!host||host.__bgWizardBound)return;host.__bgWizardBound=true;
var current=0;
var pages=[].slice.call(host.querySelectorAll('.bg-page'));
var steps=[].slice.call(host.querySelectorAll('.bg-step'));
var lines=[].slice.call(host.querySelectorAll('.bg-line'));
var back=host.querySelector('.bg-back');
var next=host.querySelector('.bg-next');
var submit=host.querySelector('.bg-submit');
var currentText=host.querySelector('[data-bg-current]');
function byName(name){return host.querySelector('[name="'+name+'"]')}
function value(name){var el=byName(name);return el&&el.value?String(el.value).trim():''}
function checked(name){return !!host.querySelector('input[name="'+name+'"]:checked')}
function checkedValues(name){return [].slice.call(host.querySelectorAll('input[name="'+name+'"]:checked')).map(function(el){return el.value})}
function emailOk(){var v=value('email');return v.indexOf('@')>0&&v.lastIndexOf('.')>v.indexOf('@')+1}
function canProceed(){if(current===0)return !!(value('first_name')&&value('last_name')&&emailOk());if(current===1)return checked('purpose_type');if(current===2)return checked('region')&&value('duration')&&value('accommodation');return checked('terms')}
var maps={purpose_type:{study:'Study & Research',work:'Work & Career',cultural:'Cultural Heritage',nature:'Nature & Eco',wellness:'Wellness Retreat',travel:'Travel & Digital Nomad'},region:{sofia:'Sofia',plovdiv:'Plovdiv',kazanlak:'Kazanlak / Rose Valley',varna:'Varna / Black Sea',bansko:'Bansko / Pirin',troyan:'Troyan / Balkan Range'},duration:{weekend:'Weekend (2-3 days)',week:'1 week',twoweeks:'2 weeks',month:'1 month',longer:'Longer than 1 month'},accommodation:{hotel:'Hotel / boutique hotel',guesthouse:'Family guesthouse',hostel:'Hostel / backpacker',apartment:'Apartment / Airbnb',eco:'Eco-lodge / rural stay'},budget:{budget:'Under EUR 40',mid:'EUR 40 - EUR 100',upper:'EUR 100 - EUR 200',luxury:'EUR 200+'}};
function radioValue(name){var el=host.querySelector('input[name="'+name+'"]:checked');return el?el.value:''}
function labelFor(name){var v=radioValue(name)||value(name);return (maps[name]&&maps[name][v])||v||'--'}
function chips(name){var vals=checkedValues(name);return vals.length?vals.map(function(v){return (maps[name]&&maps[name][v])||String(v).replace(/_/g,' ')}).join(', '):'--'}
function setText(sel,text){var el=host.querySelector(sel);if(el)el.textContent=text}
function updateSummary(){setText('[data-bg-summary="name"]',(value('first_name')+' '+value('last_name')).trim()||'--');setText('[data-bg-summary="email"]',value('email')||'--');setText('[data-bg-summary="purpose"]',labelFor('purpose_type'));setText('[data-bg-summary="region"]',labelFor('region'));setText('[data-bg-summary="stay"]',labelFor('duration')+' / '+labelFor('accommodation'));setText('[data-bg-summary="interests"]',chips('interests'));var bio=byName('bio');var cnt=host.querySelector('[data-bg-count]');if(bio&&cnt)cnt.textContent=String((bio.value||'').length)}
function show(i){current=Math.max(0,Math.min(i,pages.length-1));pages.forEach(function(p,idx){p.classList.toggle('is-active',idx===current)});steps.forEach(function(s,idx){s.classList.toggle('is-active',idx===current);s.classList.toggle('is-done',idx<current)});lines.forEach(function(l,idx){l.classList.toggle('is-done',idx<current)});if(back)back.disabled=current===0;if(next){next.hidden=current===pages.length-1;next.disabled=!canProceed()}if(submit){submit.hidden=current!==pages.length-1;submit.disabled=!canProceed()}if(currentText)currentText.textContent=String(current+1);updateSummary();setTimeout(function(){window.dispatchEvent(new Event('resize'))},0)}
function scrollToStepTop(){var target=host.querySelector('.bg-body')||host;var y=target.getBoundingClientRect().top+(window.pageYOffset||document.documentElement.scrollTop||0)-16;if(window.scrollTo)window.scrollTo({top:Math.max(0,y),behavior:'smooth'})}
var submitted=false;
function esc(s){return String(s||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
function successMarkup(){var first=host.__bgFirst||value('first_name')||'traveler';var email=host.__bgEmail||value('email')||'your email';return "<div class='mfp mfp-bulgaria bg-success-shell'><div class='bg-border'></div><div class='bg-card'><section class='bg-body'><div class='bg-stepper bg-stepper-success'><div class='bg-step is-done'><b>01</b><span>Profile</span><em>Who you are</em></div><i class='bg-line is-done'></i><div class='bg-step is-done'><b>02</b><span>Purpose</span><em>What you seek</em></div><i class='bg-line is-done'></i><div class='bg-step is-done'><b>03</b><span>Details</span><em>Preferences</em></div><i class='bg-line is-done'></i><div class='bg-step is-active'><b>04</b><span>Confirm</span><em>Review</em></div></div><div class='bg-folk'></div><div class='bg-success-panel'><div class='bg-success-check'>&#10003;</div><h2>Blagodarya, "+esc(first)+"!</h2><p>Your application has been received. We'll be in touch at <strong>"+esc(email)+"</strong> within 3 business days.</p><div class='bg-folk'></div><blockquote>Wherever you go, go with all your heart.</blockquote><button type='button' class='bg-restart' onclick='window.location.reload()'>Start a new application</button></div></section></div><p class='bg-footer'>Bulgaria Discovery Programme &copy; 2026 &middot; Sofia, Bulgaria &middot; Privacy &middot; Contact</p><div class='bg-border'></div></div>"}
function hideNativeSuccess(scope){try{(scope||document).querySelectorAll('.mf-success-message,.mf-postsubmit-pane').forEach(function(el){if(!el.closest('.bg-success-shell')){el.style.setProperty('display','none','important');el.setAttribute('hidden','hidden')}})}catch(e){}}
function revealSuccessHost(scope,anchor){try{var fields=(scope&&scope.querySelector&&scope.querySelector('[id^="mf-fields-container-"],.mf-fields-container'))||anchor;if(fields){fields.hidden=false;fields.style.setProperty('display','block','important')}if(anchor){anchor.hidden=false;anchor.style.setProperty('display','block','important')}var formEl=scope&&scope.querySelector&&scope.querySelector('.mf-form');if(formEl){formEl.hidden=false;formEl.style.removeProperty('display')}}catch(e){}}
function replaceSuccess(){if(!submitted)return false;var wrapper=host.closest('.mf-form-wrapper')||document.querySelector('.mf-form-wrapper:has(.mfp-bulgaria),.mf-form-wrapper:has(.bg-success-shell)');if(wrapper&&wrapper.querySelector('.bg-success-shell')){revealSuccessHost(wrapper,wrapper.querySelector('.bg-success-shell').parentElement);hideNativeSuccess(wrapper);return true}var nodes=[].slice.call(document.querySelectorAll('.mf-success-message,.mf-postsubmit-pane,.mf-success,.alert-success,.card,.mf-form-wrapper,.module-content'));for(var i=0;i<nodes.length;i++){var txt=(nodes[i].textContent||'').replace(/\s+/g,' ');var visible=!!(nodes[i].offsetWidth||nodes[i].offsetHeight||nodes[i].getClientRects().length);if(txt.indexOf('Submission received')>-1||txt.indexOf('Application received')>-1||txt.indexOf('Submission ID')>-1||txt.indexOf('Reference:')>-1){if(!visible&&txt.indexOf('Submission ID')<0&&txt.indexOf('Reference:')<0)continue;var scope=nodes[i].closest('.mf-form-wrapper')||wrapper||nodes[i].parentElement||document;var anchor=(scope.querySelector&&scope.querySelector('[id^="mf-fields-container-"],.mf-fields-container'))||nodes[i].parentElement||nodes[i];if(anchor&&!anchor.querySelector('.bg-success-shell')){anchor.innerHTML=successMarkup();revealSuccessHost(scope,anchor);hideNativeSuccess(scope);scrollToStepTop();return true}revealSuccessHost(scope,anchor);hideNativeSuccess(scope);return true}}return false}
function markSubmitted(){submitted=true;host.__bgFirst=value('first_name')||'traveler';host.__bgEmail=value('email')||'your email';setTimeout(replaceSuccess,350);setTimeout(replaceSuccess,1000);setTimeout(replaceSuccess,2200)}
function nativeSubmit(){var scope=host.closest('.mf-form-wrapper')||document;var native=scope.querySelector('.mf-form-actions .mf-btn-submit,.mf-btn-submit');if(native&&native!==submit){native.click();return true}return false}
var form=host.closest('form');if(form)form.addEventListener('submit',markSubmitted,true);if(submit)submit.addEventListener('click',function(e){markSubmitted();if(((submit.getAttribute('type')||'').toLowerCase()!=='submit')&&nativeSubmit()){e.preventDefault();e.stopPropagation()}},true);
if(window.MutationObserver){new MutationObserver(function(){replaceSuccess()}).observe(document.body,{childList:true,subtree:true})}
host.addEventListener('input',function(){show(current)});
host.addEventListener('change',function(){show(current)});
if(next)next.addEventListener('click',function(){if(canProceed()){show(current+1);scrollToStepTop()}});
if(back)back.addEventListener('click',function(){show(current-1);scrollToStepTop()});
show(0);
})(window.__mfCurrentScriptRoot||document);
